class Solution:
    def splitIntoFibonacci(self, num: str) -> List[int]:
        def dfs(i, a, b):
            if i == len(num):
                if a and b:
                    return [a, b]
                return []
            res = []
            for j in range(1, 11):
                if i + j > len(num):
                    break
                cur = int(num[i:i+j])
                if cur > 2**31 - 1:
                    break
                if a and a * 10 + cur > 2**31 - 1:
                    break
                if b and a + b > cur:
                    break
                if not dfs(i+j, b, a + b):
                    res.append(cur)
                    if not dfs(i+j, cur, a + b):
                        return []
            return res
        return dfs(0, 0, 0)
